CREATE OR REPLACE FUNCTION stock_ut.test_article_crud()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int;
  v_art stock.article;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);

  -- Create
  INSERT INTO stock.article (reference, designation, categorie, unite, prix_achat, tenant_id)
  VALUES ('TEST-001', 'Article test', 'bois', 'm3', 100.00, 'test')
  RETURNING id INTO v_id;

  SELECT * INTO v_art FROM stock.article WHERE id = v_id;
  RETURN NEXT ok(FOUND, 'article created');
  RETURN NEXT is(v_art.reference, 'TEST-001', 'reference matches');
  RETURN NEXT is(v_art.active, true, 'active by default');
  RETURN NEXT is(v_art.pmp, 0::numeric(12,4), 'pmp starts at 0');

  -- Update — use pg_sleep to ensure different timestamp
  PERFORM pg_sleep(0.01);
  UPDATE stock.article SET designation = 'Article modifié' WHERE id = v_id;
  SELECT * INTO v_art FROM stock.article WHERE id = v_id;
  RETURN NEXT is(v_art.designation, 'Article modifié', 'designation updated');
  RETURN NEXT ok(v_art.updated_at > v_art.created_at, 'updated_at changed');

  -- Soft delete
  UPDATE stock.article SET active = false WHERE id = v_id;
  SELECT * INTO v_art FROM stock.article WHERE id = v_id;
  RETURN NEXT is(v_art.active, false, 'soft delete works');

  -- Cleanup
  DELETE FROM stock.article WHERE tenant_id = 'test';
END;
$function$;
COMMENT ON FUNCTION stock_ut.test_article_crud() IS 'Test CRUD article: create, update, soft delete';

CREATE OR REPLACE FUNCTION stock_ut.test_article_options()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_result jsonb;
  v_row jsonb;
BEGIN
  -- Setup: create test article
  INSERT INTO stock.article (reference, designation, categorie, unite)
  VALUES ('TEST-OPT-001', 'Vis inox 5x50', 'quincaillerie', 'u');

  -- Test: returns results for matching search
  v_result := stock.article_options('inox');
  RETURN NEXT ok(jsonb_array_length(v_result) >= 1, 'search returns at least 1 result');

  v_row := v_result->0;
  RETURN NEXT ok(v_row->>'value' IS NOT NULL, 'row has value');
  RETURN NEXT ok(v_row->>'label' = 'Vis inox 5x50', 'label is designation');
  RETURN NEXT ok(v_row->>'detail' LIKE '%TEST-OPT-001%', 'detail contains reference');

  -- Test: search by reference
  v_result := stock.article_options('TEST-OPT');
  RETURN NEXT ok(jsonb_array_length(v_result) >= 1, 'search by reference works');

  -- Test: empty search returns all active
  v_result := stock.article_options(NULL);
  RETURN NEXT ok(jsonb_array_length(v_result) >= 1, 'null search returns results');

  -- Test: no match returns empty array
  v_result := stock.article_options('zzz_no_match_zzz');
  RETURN NEXT is(v_result, '[]'::jsonb, 'no match returns empty array');

  -- Cleanup
  DELETE FROM stock.article WHERE reference = 'TEST-OPT-001';
END;
$function$;
COMMENT ON FUNCTION stock_ut.test_article_options() IS 'Test article_options: returns jsonb array with value/label/detail for pgv.select_search';

CREATE OR REPLACE FUNCTION stock_ut.test_entree_reception()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_fournisseur_id int;
  v_depot_id int;
  v_art1_id int;
  v_art2_id int;
  v_result jsonb;
  v_stock numeric;
  v_pmp numeric;
BEGIN
  -- Setup: fournisseur, depot, 2 articles
  INSERT INTO crm.client (type, name) VALUES ('company', 'UT Fournisseur Reception')
  RETURNING id INTO v_fournisseur_id;

  INSERT INTO stock.depot (nom, type) VALUES ('UT Depot Reception', 'entrepot')
  RETURNING id INTO v_depot_id;

  INSERT INTO stock.article (reference, designation, categorie, unite, prix_achat, fournisseur_id)
  VALUES ('UT-REC-001', 'Chevron 60x80', 'bois', 'm', 3.50, v_fournisseur_id)
  RETURNING id INTO v_art1_id;

  INSERT INTO stock.article (reference, designation, categorie, unite, prix_achat, fournisseur_id)
  VALUES ('UT-REC-002', 'Vis 6x80', 'quincaillerie', 'u', 0.05, v_fournisseur_id)
  RETURNING id INTO v_art2_id;

  -- Test 1: reception avec 2 articles
  v_result := stock.entree_reception(jsonb_build_object(
    'reception_ref', 'REC-UT-001',
    'depot_id', v_depot_id,
    'lignes', jsonb_build_array(
      jsonb_build_object('article_id', v_art1_id, 'quantite', 20, 'prix_unitaire', 3.80),
      jsonb_build_object('article_id', v_art2_id, 'quantite', 500, 'prix_unitaire', 0.04)
    )
  ));
  RETURN NEXT ok((v_result->>'ok')::boolean, 'reception returns ok=true');
  RETURN NEXT is((v_result->>'nb_articles')::int, 2, '2 articles received');
  RETURN NEXT is((v_result->>'total_quantite')::numeric, 520::numeric, 'total qty = 520');

  -- Verify stock levels
  SELECT sum(quantite) INTO v_stock FROM stock.mouvement WHERE article_id = v_art1_id;
  RETURN NEXT is(v_stock, 20::numeric, 'art1 stock = 20');

  SELECT sum(quantite) INTO v_stock FROM stock.mouvement WHERE article_id = v_art2_id;
  RETURN NEXT is(v_stock, 500::numeric, 'art2 stock = 500');

  -- Verify PMP updated
  SELECT pmp INTO v_pmp FROM stock.article WHERE id = v_art1_id;
  RETURN NEXT is(v_pmp, 3.8000::numeric, 'art1 PMP = 3.80');

  -- Verify prix_achat updated
  SELECT prix_achat INTO v_pmp FROM stock.article WHERE id = v_art1_id;
  RETURN NEXT is(v_pmp, 3.80::numeric, 'art1 prix_achat updated');

  -- Test 2: depot invalide
  v_result := stock.entree_reception('{"depot_id": 99999, "lignes": []}'::jsonb);
  RETURN NEXT ok(NOT (v_result->>'ok')::boolean, 'invalid depot returns ok=false');

  -- Test 3: lignes vides
  v_result := stock.entree_reception(jsonb_build_object('depot_id', v_depot_id, 'lignes', '[]'::jsonb));
  RETURN NEXT ok(NOT (v_result->>'ok')::boolean, 'empty lignes returns ok=false');

  -- Test 4: article inexistant skipped
  v_result := stock.entree_reception(jsonb_build_object(
    'depot_id', v_depot_id,
    'reception_ref', 'REC-UT-002',
    'lignes', jsonb_build_array(
      jsonb_build_object('article_id', 99999, 'quantite', 10, 'prix_unitaire', 1.00),
      jsonb_build_object('article_id', v_art1_id, 'quantite', 5, 'prix_unitaire', 4.00)
    )
  ));
  RETURN NEXT is((v_result->>'nb_articles')::int, 1, 'unknown article skipped');

  -- Verify cumulative stock on art1 (20 + 5 = 25)
  SELECT sum(quantite) INTO v_stock FROM stock.mouvement WHERE article_id = v_art1_id;
  RETURN NEXT is(v_stock, 25::numeric, 'art1 cumulative stock = 25');

  -- Verify PMP recalculated (20*3.80 + 5*4.00) / 25 = 3.84
  SELECT pmp INTO v_pmp FROM stock.article WHERE id = v_art1_id;
  RETURN NEXT is(v_pmp, 3.8400::numeric, 'art1 PMP recalculated after 2nd reception');

  -- Cleanup
  DELETE FROM stock.mouvement WHERE article_id IN (v_art1_id, v_art2_id);
  DELETE FROM stock.article WHERE id IN (v_art1_id, v_art2_id);
  DELETE FROM stock.depot WHERE id = v_depot_id;
  DELETE FROM crm.client WHERE id = v_fournisseur_id;
END;
$function$;
COMMENT ON FUNCTION stock_ut.test_entree_reception() IS 'Test stock.entree_reception cross-module integration function';

